def recency_score(last_accessed: datetime, now: datetime):
    time_elapsed_hours = (now - last_accessed).total_seconds() / 3600
    # Exponential decay: score halves every 24 hours
    return 0.5 ** (time_elapsed_hours / 24)

def frequency_score(access_count: int):
    # Logarithmic scaling: more accesses = higher score, but saturates
    return math.log1p(access_count) / math.log1p(100)  # Max ~1.0 at 100 accesses

def semantic_alignment_score(memory_fact: str, query: str):
    # Cosine similarity between embeddings
    memory_vector = embed(memory_fact)
    query_vector = embed(query)
    return cosine_similarity(memory_vector, query_vector)

def apply_forgetting_curve(score: float, time_elapsed_hours: float):
    # Exponential forgetting: score halves every 24 hours
    return score * (0.5 ** (time_elapsed_hours / 24))
